301	    LookaheadConfig config;
302	    if (turn_T <= 12) {
303	        // Early game: depth 3 with fast eval at leaf
304	        config.max_depth = 3;
305	        config.samples[0] = 10;
306	        config.samples[1] = 5;
307	        config.samples[2] = 3;
308	        config.use_fast_at_leaf = true;
309	    } else {
310	        // Rest of game: depth 2 with full eval, increased samples
311	        config.max_depth = 2;
312	        config.samples[0] = 24;
313	        config.samples[1] = 6;
314	        config.samples[2] = 0;
315	        config.use_fast_at_leaf = false;
316	    }
