333	double eval_lookahead(const GameState& state_after_tilt, int turn_T_of_candy_just_processed, int depth_remaining, const LookaheadConfig& config) {
334	    if (depth_remaining == 0 || turn_T_of_candy_just_processed == NUM_TURNS) {
335	        if (config.use_fast_at_leaf) return state_after_tilt.evaluate_fast();
336	        return state_after_tilt.evaluate();
337	    }
338	
339	    int num_empty = state_after_tilt.count_empty_cells();
340	    if (num_empty == 0) {
341	        if (config.use_fast_at_leaf) return state_after_tilt.evaluate_fast();
342	        return state_after_tilt.evaluate();
343	    }
344	
345	    int next_candy_flavor = G_FLAVOR_SEQUENCE[turn_T_of_candy_just_processed];
346	    int sample_count_param_idx = config.max_depth - depth_remaining;
347	    int sample_count_this_depth = config.samples[sample_count_param_idx];
348	    int actual_num_samples = std::min(sample_count_this_depth, num_empty);
349	
350	    if (actual_num_samples == 0) {
351	        if (config.use_fast_at_leaf) return state_after_tilt.evaluate_fast();
352	        return state_after_tilt.evaluate();
353	    }
354	
355	    double sum_over_sampled_placements = 0.0;
356	    for (int s = 0; s < actual_num_samples; ++s) {
357	        int p_val;
358	        if (actual_num_samples == num_empty) {
359	            p_val = s + 1;
360	        } else {
361	            p_val = rng.uniform_int(1, num_empty);
362	        }
363	
364	        GameState S_after_placement = state_after_tilt;
365	        std::pair<int, int> candy_loc = S_after_placement.find_pth_empty_cell(p_val);
366	        S_after_placement.place_candy(candy_loc.first, candy_loc.second, next_candy_flavor);
367	        S_after_placement.turn_num_1_indexed = turn_T_of_candy_just_processed + 1;
368	
369	        double max_eval = std::numeric_limits<double>::lowest();
370	        for (int dir_idx = 0; dir_idx < NUM_DIRECTIONS; ++dir_idx) {
371	            GameState S_after_tilt = S_after_placement;
372	            S_after_tilt.apply_tilt(dir_idx);
373	            double val = eval_lookahead(S_after_tilt, S_after_placement.turn_num_1_indexed, depth_remaining - 1, config);
374	            if (val > max_eval) {
375	                max_eval = val;
376	            }
377	        }
378	        sum_over_sampled_placements += max_eval;
379	    }
380	
381	    return sum_over_sampled_placements / actual_num_samples;
382	}
