# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <array>
#include <numeric>
#include <algorithm>
#include <cmath>
#include <limits>
#include <chrono>
#include <cstring>

const int GRID_SIZE = 10;
const int NUM_TURNS = 100;
const int NUM_FLAVORS = 3;

const int DR[] = {-1, 1, 0, 0};
const int DC[] = {0, 0, -1, 1};
const char DIR_CHARS[] = {'F', 'B', 'L', 'R'};
const int NUM_DIRECTIONS = 4;

std::array<int, NUM_TURNS> G_FLAVOR_SEQUENCE;
std::array<int, NUM_FLAVORS + 1> G_flavor_total_counts;

auto G_start_time = std::chrono::steady_clock::now();

inline double elapsed_seconds() {
    auto now = std::chrono::steady_clock::now();
    return std::chrono::duration<double>(now - G_start_time).count();
}

struct XorshiftRNG {
    uint64_t x;
    XorshiftRNG() : x(88172645463325252ULL) {}

    void seed_from_clock() {
        x = std::chrono::steady_clock::now().time_since_epoch().count();
        if (x == 0) x = 1;
    }

    uint64_t next() {
        x ^= x << 13;
        x ^= x >> 7;
        x ^= x << 17;
        return x;
    }

    int uniform_int(int min_val, int max_val) {
        if (min_val >= max_val) return min_val;
        uint64_t range = static_cast<uint64_t>(max_val) - min_val + 1;
        return min_val + static_cast<int>(next() % range);
    }
};
XorshiftRNG rng;

struct Bits100 {
    uint64_t lo;
    uint64_t hi;

    Bits100() : lo(0), hi(0) {}
    Bits100(uint64_t l, uint64_t h) : lo(l), hi(h) {}

    void set_bit(int pos) {
        if (pos < 64) lo |= (1ULL << pos);
        else hi |= (1ULL << (pos - 64));
    }

    void clear_bit(int pos) {
        if (pos < 64) lo &= ~(1ULL << pos);
        else hi &= ~(1ULL << (pos - 64));
    }

    bool get_bit(int pos) const {
        if (pos < 64) return (lo >> pos) & 1;
        return (hi >> (pos - 64)) & 1;
    }

    int popcount() const {
        return __builtin_popcountll(lo) + __builtin_popcountll(hi);
    }

    bool is_zero() const { return lo == 0 && hi == 0; }

    int ctz() const {
        if (lo) return __builtin_ctzll(lo);
        if (hi) return 64 + __builtin_ctzll(hi);
        return 100;
    }

    Bits100 operator&(const Bits100& o) const { return {lo & o.lo, hi & o.hi}; }
    Bits100 operator|(const Bits100& o) const { return {lo | o.lo, hi | o.hi}; }
